require "event.BaseEvent"

AttackPropertyEvent = class("AttackPropertyEvent", BaseEvent)

function AttackPropertyEvent:onTriggered(player)
    MsgSender.sendCenterTipsToTarget(player.rakssid, 5, Messages:msgGetProperty())

    local properties = PropertyConfig:getPropertyByIds(self.config.param1)
    player.commonProperty = properties

    if self.config.time ~= -1 then
        LuaTimer:schedule(function(userId)
            local c_player = PlayerManager:getPlayerByUserId(userId)
            if not c_player then
                return
            end
            c_player.commonProperty = {}
        end, self.config.time * 1000, nil, player.userId)
    end
end

return AttackPropertyEvent